package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Files, Paths}

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serve(filename: String) = Action {
    val path = Paths.get("uploads").resolve(filename).normalize()
    if (!path.startsWith(Paths.get("uploads").toAbsolutePath.normalize()) && path.isAbsolute) {
      Forbidden("Invalid file path")
    } else if (!Files.exists(path) || Files.isDirectory(path)) {
      NotFound("File not found")
    } else {
      val source = Source.fromFile(path.toFile)
      try {
        Ok(source.mkString).as(Files.probeContentType(path))
      } finally {
        source.close()
      }
    }
  }
}